        public XmlDocument SignRequest(XmlDocument document)
        {
            var rsaKey = _certProvider.GetRsaKey();
            var certificate = _certProvider.GetCertificate();

            var signedXml = new SignedXml(document)
            {
                SigningKey = rsaKey
            };

            // Use RSA-SHA1 for legacy system compatibility
            signedXml.SignedInfo.SignatureMethod = SignedXml.XmlDsigRSASHA1Url;
            signedXml.SignedInfo.CanonicalizationMethod = SignedXml.XmlDsigExcC14NTransformUrl;

