            {
                Uri = "#" + document.DocumentElement.GetAttribute("ID"),
                DigestMethod = SignedXml.XmlDsigSHA1Url
            };

            reference.AddTransform(new XmlDsigEnvelopedSignatureTransform());
            reference.AddTransform(new XmlDsigExcC14NTransform());

            signedXml.AddReference(reference);

            // Add KeyInfo with certificate
            var keyInfo = new KeyInfo();
            keyInfo.AddClause(new KeyInfoX509Data(certificate));
            signedXml.KeyInfo = keyInfo;

            signedXml.ComputeSignature();

            var signatureElement = signedXml.GetXml();

            // Insert signature after Issuer element per SAML spec
            var issuerNode = document.DocumentElement.GetElementsByTagName("Issuer", "urn:oasis:names:tc:SAML:2.0:assertion")[0];
            if (issuerNode != null)
            {
                document.DocumentElement.InsertAfter(
                    document.ImportNode(signatureElement, true),
                    issuerNode);
            }
            else
            {
                document.DocumentElement.AppendChild(
                    document.ImportNode(signatureElement, true));
            }

            return document;
        }

        public bool VerifySignature(XmlDocument document)
        {
            var signedXml = new SignedXml(document);
            var signatureNodes = document.GetElementsByTagName("Signature", SignedXml.XmlDsigNamespaceUrl);

            if (signatureNodes.Count == 0)
                return false;

            signedXml.LoadXml((XmlElement)signatureNodes[0]);
            return signedXml.CheckSignature(_certProvider.GetRsaKey());
        }
    }

