    [ApiController]
    [Route("api/[controller]")]
    public class SamlController : ControllerBase
    {
        private readonly SamlRequestGenerator _generator;
        private readonly SamlRequestSigner _signer;
        private readonly SamlAttributeEncryptor _encryptor;
        private readonly CertificateProvider _certProvider;

        public SamlController(
            SamlRequestGenerator generator,
            SamlRequestSigner signer,
            SamlAttributeEncryptor encryptor,
            CertificateProvider certProvider)
        {
            _generator = generator;
            _signer = signer;
            _encryptor = encryptor;
            _certProvider = certProvider;
        }

        [HttpPost("authn-request")]
        public IActionResult GenerateAuthnRequest([FromBody] GenerateAuthnRequestDto dto)
        {
            try
            {
                var parameters = new SamlAuthnRequestParameters
                {
                    Id = "_" + Guid.NewGuid().ToString("N"),
                    IssueInstant = DateTime.UtcNow,
                    Destination = dto.Destination ?? "https://idp.example.com/sso",
                    AssertionConsumerServiceUrl = dto.AssertionConsumerServiceUrl ?? "https://sp.example.com/acs",
                    Issuer = dto.Issuer ?? "https://sp.example.com",
                    NameIdFormat = dto.NameIdFormat ?? "urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress",
                    AuthnContextClassRef = dto.AuthnContextClassRef ?? "urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport",
                    ForceAuthn = dto.ForceAuthn,
                    IsPassive = dto.IsPassive,
                    Conditions = new SamlConditionsParameters
                    {
                        NotBefore = DateTime.UtcNow,
                        NotOnOrAfter = DateTime.UtcNow.AddMinutes(5),
                        AudienceRestriction = dto.Issuer ?? "https://sp.example.com"
                    }
                };

                XmlDocument samlDoc;

                if (dto.Attributes != null && dto.Attributes.Count > 0)
                {
                    var attributes = dto.Attributes.Select(a => new SamlAttribute
                    {
                        Name = a.Name,
                        FriendlyName = a.FriendlyName,
                        NameFormat = "urn:oasis:names:tc:SAML:2.0:attrname-format:uri",
                        Values = a.Values ?? new List<string>(),
                        IsSensitive = a.IsSensitive
                    }).ToList();

                    samlDoc = _generator.GenerateAuthnRequestWithAttributes(parameters, attributes);

                    // Encrypt sensitive attributes
                    if (dto.EncryptSensitiveAttributes)
                    {
                        var sensitiveNames = dto.Attributes
                            .Where(a => a.IsSensitive)
                            .Select(a => a.Name)
                            .ToList();

                        if (sensitiveNames.Count > 0)
                        {
                            samlDoc = _encryptor.EncryptSensitiveAttributes(
                                samlDoc,
                                sensitiveNames,
                                _certProvider.GetRsaKey());
                        }
                    }
                }
                else
                {
                    samlDoc = _generator.GenerateAuthnRequest(parameters);
                }

                // Sign the request
                if (dto.SignRequest)
                {
                    samlDoc = _signer.SignRequest(samlDoc);
                }

                var samlXml = FormatXml(samlDoc);
                var base64Encoded = Convert.ToBase64String(Encoding.UTF8.GetBytes(samlXml));

                return Ok(new
                {
                    requestId = parameters.Id,
                    samlXml = samlXml,
                    base64EncodedRequest = base64Encoded,
                    isSigned = dto.SignRequest,
                    hasEncryptedAttributes = dto.EncryptSensitiveAttributes,
                    issueInstant = parameters.IssueInstant,
                    destination = parameters.Destination
                });
            }
            catch (Exception ex)
            {
                return BadRequest(new { error = ex.Message, details = ex.ToString() });
            }
        }

        [HttpPost("verify-signature")]
        public IActionResult VerifySignature([FromBody] VerifySignatureDto dto)
        {
            try
            {
                var doc = new XmlDocument();
                doc.PreserveWhitespace = true;

                if (!string.IsNullOrEmpty(dto.Base64EncodedRequest))
                {
                    var xml = Encoding.UTF8.GetString(Convert.FromBase64String(dto.Base64EncodedRequest));
                    doc.LoadXml(xml);
                }
                else if (!string.IsNullOrEmpty(dto.SamlXml))
                {
                    doc.LoadXml(dto.SamlXml);
                }
                else
                {
                    return BadRequest(new { error = "Provide either base64EncodedRequest or samlXml" });
                }

                var isValid = _signer.VerifySignature(doc);

                return Ok(new
                {
                    signatureValid = isValid
                });
            }
            catch (Exception ex)
            {
                return BadRequest(new { error = ex.Message });
            }
        }

        [HttpPost("encrypt-attribute")]
        public IActionResult EncryptAttribute([FromBody] EncryptAttributeDto dto)
        {
            try
            {
                // Generate a TripleDES key for standalone attribute encryption
#pragma warning disable SYSLIB0021
                using var tripleDes = TripleDES.Create();
#pragma warning restore SYSLIB0021
                tripleDes.KeySize = 192;
                tripleDes.GenerateKey();

                var result = _encryptor.EncryptAttributeValue(dto.Value, tripleDes.Key);

                // Verify round-trip
                var decrypted = _encryptor.DecryptAttributeValue(
                    result.EncryptedValue, result.IV, tripleDes.Key);

                return Ok(new
                {
                    attributeName = dto.Name,
                    encryptedValue = result.EncryptedValue,
                    iv = result.IV,
                    algorithm = result.Algorithm,
                    symmetricKey = Convert.ToBase64String(tripleDes.Key),
                    roundTripVerified = decrypted == dto.Value
                });
            }
            catch (Exception ex)
            {
                return BadRequest(new { error = ex.Message });
            }
        }

