        private string FormatXml(XmlDocument doc)
        {
            using var sw = new StringWriter();
            using var writer = new XmlTextWriter(sw)
            {
                Formatting = Formatting.Indented,
                Indentation = 2
            };
            doc.WriteTo(writer);
            writer.Flush();
            return sw.ToString();
        }
